export type BotOutcome = {
  readonly terminal: TerminalStatus;
  readonly depth: number;
  readonly turns: number;
  readonly kills: number;
  readonly hpRetention: number;
  readonly itemUses: number;
  readonly maxTurnsHit: boolean;
};

export type BotTrace = {
  readonly path: string;
  readonly content: string;
  readonly turns: readonly TraceTurnLine<RunAction, RunEvent>[];
};

export type BotRunResult = {
  readonly policy: BotPolicy["name"];
  readonly seed: string;
  readonly outcome: BotOutcome;
  readonly trace: BotTrace;
  readonly state: GameState;
};

export type RunBotOptions = {
  readonly createdAt?: string;
  readonly modelId?: string;
  readonly contentRef?: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
  readonly stallLimit?: number;
};

type StallTracker = {
  readonly previousActionKey: string | null;
  readonly previousProgressKey: string | null;
  readonly repeatCount: number;
};

const DEFAULT_CREATED_AT = "2026-06-12T00:00:00.000Z";
const DEFAULT_CONTENT_REF = {
  providerId: "fallback:old-stock",
  packVersion: "0.0.0",
} as const satisfies TraceContentRef;
const DEFAULT_STALL_LIMIT = 4;

export const runBot = (
  policy: BotPolicy,
  seed: string,
  provider: FloorContentProvider,
  maxTurns: number,
  options: RunBotOptions = {},
): BotRunResult => {
  assertMaxTurns(maxTurns);
  const started = startRun(seed, provider);
  if (!started.ok) {
    throw new Error(`failed to start run: ${started.error.message}`);
  }

  let state = started.state;
  let memory: BotMemory = createEmptyBotMemory();
  let stall: StallTracker = {
    previousActionKey: null,
    previousProgressKey: null,
    repeatCount: 0,
  };
  const createdAt = options.createdAt ?? DEFAULT_CREATED_AT;
  const runId =
    options.runId ?? traceRunId(`${policy.name}-${seed}`, createdAt);
  const recorder = createTraceRecorder<RunAction, RunEvent>({
    seed,
    createdAt,
    modelId: options.modelId ?? policy.name,
    contentRef: options.contentRef ?? DEFAULT_CONTENT_REF,
    runId,
    ...(options.writer === undefined ? {} : { writer: options.writer }),
  });
  const turns: TraceTurnLine<RunAction, RunEvent>[] = [];
  let maxTurnsHit = false;

  while (state.run.terminalStatus === "ACTIVE" && turns.length < maxTurns) {
    const view = createBotStateView(state, {
      policyName: policy.name,
      memory,
    });
    memory = updateBotMemory(memory, view);
    const decided = legalizeDecision(view, policy.decide(view));
    const breaker = breakStall(view, decided, stall, options.stallLimit);
    const action = breaker.action;
    stall = breaker.stall;

    const stepped = stepRun(state, action, provider);
    if (!stepped.ok) {
      throw new Error(
        `step failed at turn ${state.run.turn} for ${policy.name}: ${stepped.error.message}`,
      );
    }

    state = stepped.state;
    turns.push(
      recorder.recordTurn(action, {
        state: stepped.state,
        events: stepped.events,
      }),
    );

    if (action.kind === "take_hoard" && actionWasIllegal(stepped.events)) {
      const aborted = stepRun(state, { kind: "abort" }, provider);
      if (!aborted.ok) {
        throw new Error(`abort after illegal Hoard action failed: ${aborted.error.message}`);
      }
      state = aborted.state;
      turns.push(
        recorder.recordTurn(
          { kind: "abort" },
          {
            state: aborted.state,
            events: aborted.events,
          },
        ),
      );
    }
  }

  if (state.run.terminalStatus === "ACTIVE") {
    maxTurnsHit = true;
    const stepped = stepRun(state, { kind: "abort" }, provider);
    if (!stepped.ok) {
      throw new Error(`abort failed after maxTurns: ${stepped.error.message}`);
    }

    state = stepped.state;
    turns.push(
      recorder.recordTurn(
        { kind: "abort" },
        {
          state: stepped.state,
          events: stepped.events,
        },
      ),
    );
  }

  const summary = summarizeRun(state);

  return {
    policy: policy.name,
    seed,
    outcome: {
      terminal: state.run.terminalStatus,
      depth: summary.depth,
      turns: summary.turns,
      kills: summary.kills,
      hpRetention:
        state.player.hp.max <= 0 ? 0 : state.player.hp.current / state.player.hp.max,
      itemUses: turns.filter((turn) => turn.action.kind === "use_item").length,
      maxTurnsHit,
    },
    trace: {
      path: recorder.path,
      content: traceContent(recorder.header, turns),
      turns,
    },
    state,
  };
};

const legalizeDecision = (
  view: BotStateView,
  action: RunAction,
): RunAction => {
  if (hasAction(view, action)) {
    return action;
  }

  return fallbackAction(view);
};

const breakStall = (
  view: BotStateView,
  action: RunAction,
  stall: StallTracker,
  stallLimit = DEFAULT_STALL_LIMIT,
): { readonly action: RunAction; readonly stall: StallTracker } => {
  const progressKey = progressSignature(view);
  const key = actionKey(action);
  const repeatCount =
    stall.previousActionKey === key && stall.previousProgressKey === progressKey
      ? stall.repeatCount + 1
      : 1;

  if (repeatCount < stallLimit) {
    return {
      action,
      stall: {
        previousActionKey: key,
        previousProgressKey: progressKey,
        repeatCount,
      },
    };
  }

  const alternative = forcedAlternative(view, key);
  const alternativeKey = actionKey(alternative);

  return {
    action: alternative,
    stall: {
      previousActionKey: alternativeKey,
      previousProgressKey: progressKey,
      repeatCount: 1,
    },
  };
};

const forcedAlternative = (
  view: BotStateView,
  repeatedActionKey: string,
): RunAction => {
  const candidates = [
    ...view.availableActions.filter((action) => action.kind === "take_hoard"),
    ...view.availableActions.filter((action) => action.kind === "descend"),
    ...view.availableActions.filter((action) => action.kind === "pickup"),
    ...view.availableActions.filter((action) => action.kind === "attack"),
    ...view.availableActions.filter((action) => action.kind === "move"),
    ...view.availableActions.filter((action) => action.kind === "wait"),
    ...view.availableActions.filter((action) => action.kind === "use_item"),
    ...view.availableActions.filter((action) => action.kind === "abort"),
  ].filter((candidate) => actionKey(candidate) !== repeatedActionKey);

  return candidates[0] ?? { kind: "abort" };
};

const progressSignature = (view: BotStateView): string =>
  JSON.stringify({
    depth: view.run.depth,
    terminal: view.run.terminalStatus,
    position: view.player.position,
    hp: view.player.hp.current,
    fullness: view.player.fullness.current,
    inventory: view.player.inventory.map((item) => [
      item.itemInstanceId,
      item.definitionId,
      item.quantity,
    ]),
    enemies: view.visible.enemies.map((enemy) => [
      enemy.id,
      enemy.position,
      enemy.hp.current,
    ]),
    features: view.visible.features.map((feature) => [
      feature.id,
      feature.position,
    ]),
  });

const traceContent = (
  header: Parameters<typeof JSON.stringify>[0],
  turns: readonly TraceTurnLine<RunAction, RunEvent>[],
): string =>
  [JSON.stringify(header), ...turns.map((turn) => JSON.stringify(turn))].join(
    "\n",
  ) + "\n";

const assertMaxTurns = (maxTurns: number): void => {
  if (!Number.isSafeInteger(maxTurns) || maxTurns <= 0) {
    throw new RangeError("maxTurns must be a positive safe integer");
  }
};

const actionWasIllegal = (events: readonly RunEvent[]): boolean =>
  events.some(
    (event) =>
      (event.type === "run_action_illegal" || event.type === "action_illegal") &&
      "actionKind" in event.data,
  );

import type { FloorContentProvider } from "../../engine/run/loop.js";
import type { BotPolicy } from "./types.js";
import { runBot, type BotRunResult, type RunBotOptions } from "./driver.js";

export type BotBatchRow = {
  readonly policy: BotPolicy["name"];
  readonly seed: string;
  readonly terminal: string;
  readonly depth: number;
  readonly turns: number;
  readonly kills: number;
  readonly hpRetention: number;
  readonly itemUses: number;
  readonly tracePath: string;
};

export type BotBatchResult = {
  readonly rows: readonly BotBatchRow[];
  readonly runs: readonly BotRunResult[];
};

export const runBotBatch = (
  policies: readonly BotPolicy[],
  seeds: readonly string[],
  providerFactory: () => FloorContentProvider,
  maxTurns: number,
  options: RunBotOptions = {},
): BotBatchResult => {
  const runs = policies.flatMap((policy) =>
    seeds.map((seed) =>
      runBot(policy, seed, providerFactory(), maxTurns, {
        ...options,
        runId: `bot-${policy.name}-${seed}`,
      }),
    ),
  );

  return {
    runs,
    rows: runs.map((run) => ({
      policy: run.policy,
      seed: run.seed,
      terminal: run.outcome.terminal,
      depth: run.outcome.depth,
      turns: run.outcome.turns,
      kills: run.outcome.kills,
      hpRetention: run.outcome.hpRetention,
      itemUses: run.outcome.itemUses,
      tracePath: run.trace.path,
    })),
  };
};

export const formatBotOutcomeTable = (
  rows: readonly BotBatchRow[],
): string => {
  const headers = [
    "policy",
    "seed",
    "terminal",
    "depth",
    "turns",
    "kills",
    "hp%",
    "itemUses",
  ] as const;
  const body = rows.map((row) => [
    row.policy,
    row.seed,
    row.terminal,
    row.depth.toString(),
    row.turns.toString(),
    row.kills.toString(),
    Math.round(row.hpRetention * 100).toString(),
    row.itemUses.toString(),
  ]);
  const widths = headers.map((header, index) =>
    Math.max(header.length, ...body.map((row) => row[index]?.length ?? 0)),
  );
  const line = (cells: readonly string[]) =>
    cells
      .map((cell, index) => cell.padEnd(widths[index] ?? cell.length))
      .join(" | ");

  return [
    line(headers),
    widths.map((width) => "-".repeat(width)).join("-|-"),
    ...body.map(line),
  ].join("\n");
};

import { mkdtempSync, readFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";

import { describe, expect, it } from "vitest";

import { cautiousPolicy, balancedPolicy } from "../harness/bots/policies/index.js";
import {
  parseSeeds,
  parseSimulateArgs,
  runSimulate,
  SIMULATE_HELP_TEXT,
} from "./simulate.js";

const MINI_POLICIES = [cautiousPolicy.name, balancedPolicy.name] as const;
const LOW_MAX_TURNS = 8;

let seedCounter = 0;

const uniqueSeeds = (): [string, string] => {
  seedCounter += 1;
  const suffix = `${seedCounter}-${Date.now()}`;
  return [`cli-sim-a-${suffix}`, `cli-sim-b-${suffix}`];
};

describe("simulate args", () => {
  it("parses single and batch modes", () => {
    expect(parseSimulateArgs(["--help"]).help).toBe(true);
    expect(parseSimulateArgs(["--policy", "cautious", "--seed", "abc"])).toEqual({
      help: false,
      batch: false,
      policy: "cautious",
      seed: "abc",
      maxTurns: 900,
      outPath: null,
    });
    expect(
      parseSimulateArgs([
        "--batch",
        "--policies",
        "cautious,balanced",
        "--seeds",
        "2",
        "--max-turns",
        "12",
        "--out",
        "out.json",
      ]),
    ).toEqual({
      help: false,
      batch: true,
      policies: ["cautious", "balanced"],
      seeds: ["simulate-1", "simulate-2"],
      maxTurns: 12,
      outPath: "out.json",
    });
  });

  it("expands numeric and list seeds", () => {
    expect(parseSeeds("3")).toEqual(["simulate-1", "simulate-2", "simulate-3"]);
    expect(parseSeeds("one,two")).toEqual(["one", "two"]);
  });

  it("documents help text", () => {
    expect(SIMULATE_HELP_TEXT).toContain("--batch");
    expect(SIMULATE_HELP_TEXT).toContain("--max-turns");
  });
});

describe("simulate runs", () => {
  it("runs a small batch, prints a sane table, and writes JSON", () => {
    const outDir = mkdtempSync(join(tmpdir(), "gg-simulate-"));
    const outPath = join(outDir, "batch.json");
    const seeds = uniqueSeeds();

    const result = runSimulate({
      help: false,
      batch: true,
      policies: [...MINI_POLICIES],
      seeds,
      maxTurns: LOW_MAX_TURNS,
      outPath,
    });

    expect(result.rows).toHaveLength(4);
    expect(result.table).toContain("policy");
    expect(result.table).toContain("terminal");
    expect(result.table).toContain("cautious");
    expect(result.table).toContain("balanced");
    expect(result.table.split("\n")).toHaveLength(6);

    const json = JSON.parse(readFileSync(outPath, "utf8")) as {
      rows: Array<{ policy: string; seed: string; terminal: string }>;
      hasFailures: boolean;
    };
    expect(json.rows).toHaveLength(4);
    expect(json.hasFailures).toBe(result.exitCode !== 0);
  }, 60_000);

  it("returns a nonzero exit code when runs hit the turn cap", () => {
    const result = runSimulate({
      help: false,
      batch: true,
      policies: [cautiousPolicy.name],
      seeds: [`cli-sim-cap-${++seedCounter}-${Date.now()}`],
      maxTurns: 1,
      outPath: null,
    });

    expect(result.exitCode).toBe(1);
    expect(result.rows[0]?.terminal).not.toBe("ACTIVE");
  }, 30_000);
});

import { config } from "../config/index.js";
import type {
  FloorContent,
  FloorContentProvider,
  HoardFeatureParams,
} from "../engine/run/loop.js";
import {
  FallbackContentValidationError,
  getFallbackFloor,
  loadFallbackContentPack,
  type FallbackContentPack,
  type ResolvedFallbackFloor,
} from "./content-loader.js";

export type FallbackProviderErrorCode =
  | "fallback_content_invalid"
  | "fallback_depth_unavailable";

export class FallbackProviderError extends Error {
  readonly kind = "fallback-provider-error";
  readonly code: FallbackProviderErrorCode;
  readonly depth: number | null;
  readonly file: string | null;
  readonly entityId: string | null;
  readonly source: unknown;

  constructor(
    code: FallbackProviderErrorCode,
    depth: number | null,
    message: string,
    source: unknown,
  ) {
    super(message);
    this.name = "FallbackProviderError";
    this.code = code;
    this.depth = depth;
    this.source = source;

    if (source instanceof FallbackContentValidationError) {
      this.file = source.file;
      this.entityId = source.entityId;
      return;
    }

    this.file = null;
    this.entityId = null;
  }
}

export type FallbackFloorContentProviderOptions = {
  readonly root?: URL;
  readonly hoard?: HoardFeatureParams;
};

const DEFAULT_HOARD: HoardFeatureParams = {
  id: "hoard",
  name: "The Hoard",
  hint: { distance: "far_from_entrance" },
};

export class FallbackFloorContentProvider implements FloorContentProvider {
  readonly pack: FallbackContentPack;
  private readonly floors: ReadonlyMap<number, ResolvedFallbackFloor>;
  private readonly hoard: HoardFeatureParams;

  constructor(options: FallbackFloorContentProviderOptions = {}) {
    this.hoard = options.hoard ?? DEFAULT_HOARD;

    try {
      this.pack = loadFallbackContentPack(options.root);
      this.floors = validateFloors(this.pack);
    } catch (error) {
      if (error instanceof FallbackProviderError) {
        throw error;
      }

      throw wrapProviderError("fallback_content_invalid", null, error);
    }
  }

  getFloor(depth: number, seed: string): FloorContent {
    const floor = this.floors.get(depth);
    if (floor === undefined) {
      throw new FallbackProviderError(
        "fallback_depth_unavailable",
        depth,
        `fallback floor ${depth} is not available`,
        null,
      );
    }

    return {
      params: {
        ...floor.params,
        seed,
        ...(depth === config.runStructure.depthFloors
          ? { hoard: this.hoard }
          : {}),
      },
      roster: floor.roster,
      items: floor.items,
      traps: floor.traps,
      npcs: floor.npcs,
      ...(floor.quest === null ? {} : { quest: floor.quest }),
    };
  }
}

export const createFallbackFloorContentProvider = (
  options: FallbackFloorContentProviderOptions = {},
): FallbackFloorContentProvider => new FallbackFloorContentProvider(options);

const validateFloors = (
  pack: FallbackContentPack,
): ReadonlyMap<number, ResolvedFallbackFloor> => {
  const floors = new Map<number, ResolvedFallbackFloor>();

  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
    try {
      floors.set(depth, getFallbackFloor(pack, depth));
    } catch (error) {
      throw wrapProviderError("fallback_content_invalid", depth, error);
    }
  }

  return floors;
};

const wrapProviderError = (
  code: FallbackProviderErrorCode,
  depth: number | null,
  source: unknown,
): FallbackProviderError => {
  const sourceMessage = source instanceof Error ? source.message : String(source);
  const message =
    depth === null
      ? `fallback content pack is invalid: ${sourceMessage}`
      : `fallback floor ${depth} is invalid: ${sourceMessage}`;

  return new FallbackProviderError(code, depth, message, source);
};

